module top_module(
    input [7:0]exponent,
    input clk, clear, load,
    output reg [7:0]saved_exp
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        if(clear)
            saved_exp <= 8'b0;
        else if(load)
            saved_exp <= exponent;

endmodule
